// // This module selects between two 32-bit inputs, IN0 and IN1, based on the value of the SEL signal. When SEL is high (1), the output OUT is assigned the value of IN0; when SEL is low (0), OUT takes the value of IN1.
module top_module(
    input SEL,
    input [31:0] IN0,
    input [31:0] IN1,

    output reg [31:0] OUT
    );always @(SEL,IN0,IN1)
        case (SEL)
            1'b0: OUT <= IN0;
            1'b1: OUT <= IN1;
        endcase    

endmodule
